public static string Camelize(this string input)
{
    var pascalized = input.Pascalize();
    if (pascalized.Length == 0)
    {
        return pascalized;
    }

    var firstLower = char.ToLowerInvariant(pascalized[0]);
    if (firstLower == pascalized[0])
    {
        return pascalized;
    }

    return string.Create(pascalized.Length, (pascalized, firstLower), (span, state) =>
    {
        state.pascalized.AsSpan().CopyTo(span);
        span[0] = state.firstLower;
    });
}

