302.         var inWord = false;
303.         foreach (var c in input)
304.         {
305.             if (char.IsLetterOrDigit(c))
306.             {
307.                 if (!inWord)
308.                 {
309.                     count++;
310.                     inWord = true;
311.                 }
312.             }
313.             else
314.             {
315.                 inWord = false;
316.             }
317.         }
318. 
319.         return count;
320.     }
